def p(g):R=len(g);C=len(g[0]);A={(i,j)for i,r in enumerate(g)for j,v in enumerate(r)if v==2};B={(i,j)for i,r in enumerate(g)for j,v in enumerate(r)if v==8};r1,r2=min(A)[0],max(A)[0];c1,c2=min(j for i,j in A),max(j for i,j in A);r3,r4=min(B)[0],max(B)[0];c3,c4=min(j for i,j in B),max(j for i,j in B);O1=c2>=c3 and c4>=c1;O2=r2>=r3 and r4>=r1;dy=((r3-r2-1)*(r2<r3)+(r4-r1+1)*(r1>r4))*O1;dx=((c3-c2-1)*(c2<c3)+(c4-c1+1)*(c1>c4))*O2;return[[8if(i,j)in B else 2if(i-dy,j-dx)in A else 0for j in range(C)]for i in range(R)]
